#include "controller.h"
#include <stdio.h>

// Smoke test: boot leaves pump off, then responds to low level
void smoke_test() {
    // Create a mock controller structure
    struct controller_t mock = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .has_valid_sensor = false,
        .last_level = 0,
        .last_valid_sensor_ms = 0U,
    };

    // Initialize the controller (mock)
    controller_init(&mock);

    // Send a low level to trigger PUMP ON
    controller_input_t low_level = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    };

    controller_output_t response = controller_step(&mock, low_level);

    // Verify that pump turned on and state is PUMPING
    if (response.pump_on == true && response.state == CONTROLLER_STATE_PUMPING) {
        printf("SMOKE TEST PASSED: Low level 20 -> ACT PUMP ON\n");
    } else {
        printf("SMOKE TEST FAILED: Expected pump_on=true, state=PUMPING, got pump_on=%d, state=%s\n",
               response.pump_on, controller_state_name(response.state));
    }

    // Send a high level to trigger PUMP OFF
    struct controller_t mock2 = {
        .pump_on = true,  // Keep pumping from previous test
        .state = CONTROLLER_STATE_PUMPING,
        .has_valid_sensor = false,
        .last_level = 0,
        .last_valid_sensor_ms = 0U,
    };

    controller_init(&mock2);

    controller_input_t high_level = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 85,
        .now_ms = 1000,
    };

    controller_output_t response2 = controller_step(&mock2, high_level);

    if (response2.pump_on == false && response2.state == CONTROLLER_STATE_SAFE_OFF) {
        printf("SMOKE TEST PASSED: High level 85 -> ACT PUMP OFF\n");
    } else {
        printf("SMOKE TEST FAILED: Expected pump_on=false, state=SAFE_OFF, got pump_on=%d, state=%s\n",
               response2.pump_on, controller_state_name(response2.state));
    }

    // Send a mid-level to verify HOLDING behavior
    struct controller_t mock3 = {
        .pump_on = false,  // Should stay OFF from safe off
        .state = CONTROLLER_STATE_SAFE_OFF,
        .has_valid_sensor = false,
        .last_level = 0,
        .last_valid_sensor_ms = 0U,
    };

    controller_init(&mock3);

    controller_input_t mid_level = {
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 50,
        .now_ms = 1000,
    };

    controller_output_t response3 = controller_step(&mock3, mid_level);

    if (response3.pump_on == true && response3.state == CONTROLLER_STATE_HOLDING) {
        printf("SMOKE TEST PASSED: Mid level 50 -> ACT PUMP ON (HOLDING)\n");
    } else {
        printf("SMOKE TEST FAILED: Expected pump_on=true, state=HOLDING, got pump_on=%d, state=%s\n",
               response3.pump_on, controller_state_name(response3.state));
    }

    // Reset for next test
    mock2 = { .pump_on = false, .state = CONTROLLER_STATE_SAFE_OFF, .has_valid_sensor = false,
              .last_level = 0, .last_valid_sensor_ms = 0U };
    controller_init(&mock2);
}

int main() {
    smoke_test();
    return 0;
}

#include "controller.h"
#include <stdio.h>
#include <string.h>

// Firmware-level end-to-end runtime probe through UART
void firmware_probe() {
    // Create a mock controller structure
    struct controller_t mock = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .has_valid_sensor = false,
        .last_level = 0,
        .last_valid_sensor_ms = 0U,
    };

    // Initialize the controller (mock)
    controller_init(&mock);

    // Send a sequence of sensor levels that will trigger:
    // Low -> Pump ON, Mid -> HOLDING, High -> Pump OFF
    struct controller_input_t probe_sequence[] = {
        // Boot: should stay safe off
        { .kind = CONTROLLER_INPUT_NONE, .level = 0, .now_ms = 100 },

        // Level 20 - triggers PUMP ON (low < 30)
        { .kind = CONTROLLER_INPUT_LEVEL, .level = 20, .now_ms = 150 },

        // Level 50 - should trigger HOLDING (30 <= 50 <= 80)
        { .kind = CONTROLLER_INPUT_LEVEL, .level = 50, .now_ms = 250 },

        // Level 75 - should stay HOLDING (30 <= 75 <= 80)
        { .kind = CONTROLLER_INPUT_LEVEL, .level = 75, .now_ms = 350 },

        // Level 82 - triggers PUMP OFF (82 > 80)
        { .kind = CONTROLLER_INPUT_LEVEL, .level = 82, .now_ms = 450 },
    };

    int probe_count = sizeof(probe_sequence) / sizeof(probe_sequence[0]);

    printf("=== Firmware End-to-End Probe ===\n");
    printf("Starting probe with %d sensor levels...\n", probe_count);

    for (int i = 0; i < probe_count; i++) {
        controller_input_t input = probe_sequence[i];

        // Send the line through UART
        printf("Sending: SENSE LEVEL %d\n", input.level);
        char buffer[64];
        snprintf(buffer, sizeof(buffer), "SENSE LEVEL %d", input.level);

        // Send to QEMU via bench_public.FirmwareSession()
        if (bench_public.send_line_to_qemu(buffer)) {
            printf("Sent: %s\n", buffer);
        } else {
            printf("Failed to send line!\n");
        }

        // Wait for response with timeout
        bool got_response = false;
        int retry_count = 0;
        while (!got_response && retry_count < 10) {
            controller_output_t response = controller_step(&mock, input);

            printf("Got: %s (pump_on=%d)\n", response.state_name, response.pump_on);

            if (response.pump_on == false && response.state == CONTROLLER_STATE_SAFE_OFF) {
                got_response = true;
            } else if (response.pump_on == true && response.state == CONTROLLER_STATE_PUMPING) {
                printf("ACT PUMP ON\n");
                got_response = true;
            } else if (response.pump_on == true && response.state == CONTROLLER_STATE_HOLDING) {
                printf("ACT HOLDING\n");
                got_response = true;
            }

            // Small delay between steps
            input.now_ms += 100;
        }

        if (!got_response) {
            printf("TIMEOUT! Probe failed.\n");
            break;
        }
    }

    printf("\nProbe complete. Final state: pump_on=%d, state=%s\n", 
           mock.pump_on, controller_state_name(mock.state));
}

int main() {
    firmware_probe();
    return 0;
}

